import React from 'react';

const skillsData = [
  { name: 'HTML & CSS', level: 85, description: 'Responsive UI building' },
  { name: 'JavaScript', level: 70, description: 'Core JS concepts' },
  { name: 'React', level: 60, description: 'Component-based apps' },
];

const Skills = () => (
  <section
    id="Skills"
    style={{ background: '#0a192f', fontFamily: "'Orbitron', sans-serif" }}
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
  >
    <h1 className="text-white text-4xl font-bold mb-12">Skills</h1>

    <div className="w-full max-w-2xl flex flex-col gap-5">
      {skillsData.map((s, i) => (
        <div
          key={i}
          style={{
            background: '#f8f9fa',
            borderLeft: '5px solid #0d6efd',
            borderRadius: '12px',
            padding: '20px',
          }}
        >
          <h3 style={{ color: '#0b1f3a' }}>{s.name}</h3>
          <p>{s.description}</p>
          <p>{s.level}%</p>
        </div>
      ))}
    </div>
  </section>
);

export default Skills;
